import os
from subprocess import call

def convert_image(event, context):
    # extract filename and conversion options from the Cloud Storage notification metadata
    file_name = event['name']
    
    # For simplicity, I will assume that the conversion options are contained in the filename itself. 
    # In a real-world application, you would need to implement more robust parsing logic here
    convert_options = os.path.splitext(file_name)[0].split('_')[1:]
    
    # build command string for ImageMagick's 'convert' utility
    cmd = f"convert {'_'.join(convert_options)} {os.path.join('gs://your-bucket', file_name)} {os.path.join('gs://converted-images-bucket', file_name)}"
    
    # execute the command with subprocess.call()
    call([cmd], shell=True)